def cal_sum(n):
    if not isinstance(n, int):
        raise TypeError("Argument must be an integer.")
    if n < 0:
        raise ValueError("Argument must be a non-negative integer.")

    if n == 0:
        return 3
    elif n == 1:
        return 3
    elif n == 2:
        return 5
    else:
        sum_total = 5
        a, b, c = 3, 0, 2
        for i in range(3, n + 1):
            next_p = a + b
            sum_total += next_p
            a, b, c = b, c, next_p
        return sum_total

