def last_Digit_Factorial(n):
    if n < 0:
        return None
    if n == 0 or n == 1:
        return 1

    last_digit = 1
    for i in range(2, n + 1):
        last_digit = (last_digit * i) % 10

    return last_digit

def multiply_num(numbers):
    product = 1
    for num in numbers:
        product *= num
    length = len(numbers)
    return product / length

def convert_list_dictionary(list1, list2, list3):
    # Validate input types
    if not all(isinstance(lst, list) for lst in [list1, list2, list3]):
        raise TypeError("All arguments must be of type list.")

    # Validate that all lists have the same length
    if not all(len(lst) == len(list1) for lst in [list2, list3]):
        raise ValueError("All input lists must have the same length.")

    # Validate that all elements in list1 are strings
    if not all(isinstance(item, str) for item in list1):
        raise TypeError("All elements in the first list must be strings.")

    # Validate that all elements in list2 are strings
    if not all(isinstance(item, str) for item in list2):
        raise TypeError("All elements in the second list must be strings.")

    # Validate that all elements in list3 are integers
    if not all(isinstance(item, int) for item in list3):
        raise TypeError("All elements in the third list must be integers.")

    # Validate that all elements in list3 are non-negative integers
    if not all(item >= 0 for item in list3):
        raise ValueError("All elements in the third list must be non-negative integers.")

    return [{k: {v: w}} for k, v, w in zip(list1, list2, list3)]

