class RemoveElementsProcessor:
    def __init__(self):
        self._cache = {}

    def clear_cache(self):
        self._cache.clear()

    def remove_elements(self, list1, list2):
        def convert_to_number(value):
            try:
                # Try converting to integer first
                return int(value)
            except ValueError:
                try:
                    # Try converting to float
                    return float(value)
                except ValueError:
                    # Raise error if conversion is not possible
                    raise ValueError(f"Cannot convert {value} to a number.")

        # Validate types of the inputs
        if not isinstance(list1, list):
            raise TypeError("The first argument must be a list.")
        if not isinstance(list2, list):
            raise TypeError("The second argument must be a list.")

        # Convert elements of list1 and list2 to numbers if they are strings
        try:
            list1 = [convert_to_number(x) if isinstance(x, str) else x for x in list1]
            list2 = [convert_to_number(x) if isinstance(x, str) else x for x in list2]
        except ValueError as e:
            raise ValueError(str(e))

        # Validate values of the lists (checking if they contain only hashable elements)
        try:
            set(list1)
            set(list2)
        except TypeError:
            raise ValueError("Both lists must contain only hashable elements.")

        # Create a cache key based on the arguments
        cache_key = (tuple(list1), tuple(list2))

        # Check if the result is already in the cache
        if cache_key in self._cache:
            return self._cache[cache_key]

        # Use list comprehension to filter out elements present in list2
        result = [element for element in list1 if element not in list2]

        # Store the result in the cache
        self._cache[cache_key] = result

        return result

    def remove_elements_batch(self, arg_tuples):
        results = []
        for list1, list2 in arg_tuples:
            try:
                result = self.remove_elements(list1, list2)
                results.append(result)
            except Exception:
                results.append(None)
        return results

