import logging

class OverlappingProcessor:
    def __init__(self):
        self._cache = {}
        self.stats = {'calls': 0, 'cache_hits': 0, 'errors': 0}
        self.logger = logging.getLogger('overlapping')
        self.logger.setLevel(logging.DEBUG)

    def clear_cache(self):
        self._cache.clear()

    def get_stats(self):
        return self.stats.copy()

    def overlapping(self, seq1, seq2):
        """
        Optimized version of overlapping check with O(n) time complexity.

        The optimization strategy is to convert both sequences to sets, which allows for O(1) membership checks.
        This is more efficient than the original O(n) time complexity of the any() function with a generator expression.
        """
        self.stats['calls'] += 1
        key = (tuple(seq1), tuple(seq2))
        self.logger.debug(f'overlapping({seq1}, {seq2})')
        if key in self._cache:
            self.logger.debug(f'Cache hit: {key}')
            self.stats['cache_hits'] += 1
            return self._cache[key]
        try:
            if not isinstance(seq1, (list, tuple)) or not isinstance(seq2, (list, tuple)):
                raise TypeError("Both arguments must be sequences (lists or tuples).")
            if not all(isinstance(x, (int, float)) or (isinstance(x, str) and x.replace('.', '', 1).replace('-', '', 1).isdigit()) for x in seq1) or \
               not all(isinstance(x, (int, float)) or (isinstance(x, str) and x.replace('.', '', 1).replace('-', '', 1).isdigit()) for x in seq2):
                raise TypeError("All elements in the sequences must be numbers or strings.")
            if not all(isinstance(x, (int, float)) or (isinstance(x, str) and x.replace('.', '', 1).replace('-', '', 1).isdigit()) for x in seq1) or \
               not all(isinstance(x, (int, float)) or (isinstance(x, str) and x.replace('.', '', 1).replace('-', '', 1).isdigit()) for x in seq2):
                raise TypeError("All string elements in the sequences must be numeric.")
            try:
                seq1 = set(float(x) if isinstance(x, str) else x for x in seq1)
                seq2 = set(float(x) if isinstance(x, str) else x for x in seq2)
            except ValueError:
                raise ValueError("Invalid numeric string in the sequence.")
            if len(seq1) == 0 or len(seq2) == 0:
                raise ValueError("Sequences cannot be empty.")
            result = bool(seq1 & seq2)
            self._cache[key] = result
            self.logger.debug(f'Result: {result}')
            return result
        except Exception as e:
            self.logger.warning(f'Exception: {e}')
            self.stats['errors'] += 1
            return None

    def overlapping_batch(self, args):
        results = []
        for arg in args:
            try:
                results.append(self.overlapping(*arg))
            except Exception as e:
                self.logger.warning(f'Exception: {e}')
                self.stats['errors'] += 1
                results.append(None)
        return results

