def first_Digit(n):
    # Input type validation
    if not isinstance(n, (int, float)):
        raise TypeError("The argument must be an integer or a float.")

    # Input value validation
    if isinstance(n, float) and n.is_integer():
        n = int(n)
    elif isinstance(n, float):
        raise ValueError("The argument must be a whole number if it is a float.")
    else:
        n = int(n)

    if n == 0:
        raise ValueError("The argument cannot be zero.")

    n = abs(n)
    while n >= 10:
        n = n // 10
    return n

