# Module-level cache
_cache = {}

def clear_cache():
    """Empty the cache for combinations_list function."""
    global _cache
    _cache = {}

def combinations_list(lst):
    # Input validation
    if not isinstance(lst, list):
        raise TypeError("Input must be a list")

    # Create a processed copy with converted string representations
    processed_lst = []
    for i, item in enumerate(lst):
        # Convert string representations of numbers
        if isinstance(item, str):
            try:
                # Try to convert to int first, then float if that fails
                try:
                    converted = int(item)
                except ValueError:
                    converted = float(item)
                processed_lst.append(converted)
            except (ValueError, TypeError):
                # If conversion fails, keep the original string
                processed_lst.append(item)
        else:
            processed_lst.append(item)

    # Check for invalid values (non-hashable elements that would break combinations)
    for i, item in enumerate(processed_lst):
        try:
            hash(item)
        except TypeError:
            raise ValueError(f"Element at index {i} is not hashable: {repr(item)}. "
                           "All elements must be hashable for combinations.")

    # Create cache key - convert list to tuple for hashability
    cache_key = tuple(processed_lst)

    # Check cache
    if cache_key in _cache:
        return _cache[cache_key]

    # Compute result if not in cache
    result = []
    n = len(processed_lst)
    for r in range(n + 1):
        for combo in combinations(processed_lst, r):
            result.append(list(combo))

    # Store in cache
    _cache[cache_key] = result

    return result

def combinations_list_batch(arg_tuples):
    """
    Process a batch of arguments for combinations_list.

    Args:
        arg_tuples: A list where each element is a tuple containing a single list argument
                   for combinations_list.

    Returns:
        A list of results, where each result corresponds to the input at the same position.
        If an exception occurs for a particular input, None is placed at that position.
    """
    if not isinstance(arg_tuples, list):
        raise TypeError("arg_tuples must be a list")

    results = []
    for i, arg_tuple in enumerate(arg_tuples):
        if not isinstance(arg_tuple, tuple):
            raise TypeError(f"Element at index {i} must be a tuple")

        if len(arg_tuple) != 1:
            raise ValueError(f"Tuple at index {i} must contain exactly 1 element (a list)")

        try:
            result = combinations_list(arg_tuple[0])
            results.append(result)
        except Exception:
            results.append(None)

    return results

