    def __init__(self):
        self._cache = {}

    def clear_cache(self):
        self._cache.clear()

    def fib(self, n: int or str):
        """Return n-th Fibonacci number.
        >>> fib(10)
        55
        >>> fib(1)
        1
        >>> fib(8)
        21
        """
        # Check if n is of correct type
        if not isinstance(n, (int, str)):
            raise TypeError("n must be an integer or a string")

        # Now process n to get integer value
        if isinstance(n, int):
            num = n
        else:
            try:
                num_float = float(n)
            except ValueError:
                raise ValueError(f"could not convert string '{n}' to a float")
            if not num_float.is_integer():
                raise ValueError(f"Input '{n}' is not an integer after conversion")
            num = int(num_float)

        # Now validate num is a positive integer
        if num < 1:
            raise ValueError("n must be a positive integer")

        # Check cache
        if num in self._cache:
            return self._cache[num]

        # Proceed with original computation
        if num == 1:
            result = 1
        elif num == 2:
            result = 1
        else:
            a, b = 1, 1
            for _ in range(3, num + 1):
                a, b = b, a + b
            result = b

        # Store in cache
        self._cache[num] = result
        return result

