        """Process a list of Fibonacci arguments and return results.
        Each element in args_list must be a tuple containing a single argument for fib.
        If any call raises an exception, None is placed in the result list at that position.
        """
        results = []
        for args in args_list:
            try:
                result = self.fib(args[0])
                results.append(result)
            except Exception:
                results.append(None)
        return results

