import re

def find_adverb_position(sentence):
    # Input validation and conversion
    if isinstance(sentence, (int, float)):
        sentence = str(sentence)
    elif isinstance(sentence, str):
        try:
            # Attempt to convert string representations of numbers
            float(sentence)
        except ValueError:
            pass
