        raise TypeError("The sentence must be a string or a numeric type.")

    if not sentence:
        raise ValueError("The sentence cannot be empty.")

    # Regular expression to match adverbs ending with 'ly'
    adverb_pattern = r'\b\w+ly\b'
    match = re.search(adverb_pattern, sentence)
    if match:
        start_pos = match.start()
        end_pos = match.end()
        adverb = match.group()
        return (start_pos, end_pos, adverb)
    return None

