        raise TypeError("All elements in the list must be numbers or their string representations.")
    if len(numbers) == 0:
        raise ValueError("Input list must not be empty.")

    try:
        numbers = [float(x) if isinstance(x, str) else x for x in numbers]
    except ValueError:
        raise ValueError("Invalid string representation of a number.")

    mean = statistics.mean(numbers)
