def count_Substrings(s):
    # Validate input type
    if not isinstance(s, str):
        raise TypeError("Input must be a string.")

    # Attempt to convert the string to a float
    try:
        float_value = float(s)
    except ValueError:
        raise ValueError("Input string must be a valid numeric representation.")

    # Convert the float back to a string without decimal points for processing
    if '.' in s:
        s = s.replace('.', '')
    else:
        s = str(int(float_value))

    # Validate input value
    if not s.isnumeric():
        raise ValueError("Input string must contain only numeric characters after conversion.")

    n = len(s)
    count = 0

    # Iterate over each character in the string
    for i in range(n):
        sum = 0
        # Check all substrings starting from the current character
        for j in range(i, n):
            # Add the numeric value of the current character to the sum
            sum += ord(s[j]) - ord('0')
            # If the sum equals the length of the substring, increment the count
            if sum == (j - i + 1):
                count += 1

    return count

