        raise TypeError("The size of the heap and index must be integers.")
    if n < 0 or i < 0 or i >= n:
        raise ValueError("The size of the heap and index must be non-negative and index must be less than the size of the heap.")

    largest = i
    left = 2 * i + 1
    right = 2 * i + 2

    if left < n and arr[i] < arr[left]:
        largest = left

    if right < n and arr[largest] < arr[right]:
        largest = right

    if largest != i:
        arr[i], arr[largest] = arr[largest], arr[i]
        heapify(arr, n, largest)

