def change_date_format(date_str):
    if not isinstance(date_str, str):
        raise TypeError("Input must be a string.")

    if len(date_str) != 10 or date_str[4] != '-' or date_str[7] != '-':
        raise ValueError("Date string must be in 'yyyy-mm-dd' format.")

    parts = date_str.split('-')
    if len(parts) != 3:
        raise ValueError("Date string must be in 'yyyy-mm-dd' format.")

    try:
        year = float(parts[0])
        month = float(parts[1])
        day = float(parts[2])
    except ValueError:
        raise ValueError("Year, month, and day must be valid numeric values.")

    if not (year.is_integer() and month.is_integer() and day.is_integer()):
        raise ValueError("Year, month, and day must be valid integers.")

    year = int(year)
    month = int(month)
    day = int(day)

    if not (1 <= month <= 12):
        raise ValueError(f"Month must be between 1 and 12, got {month}.")

    # Days in each month (not accounting for leap years)
    month_days = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]

    if month == 2 and (year % 4 == 0 and (year % 100 != 0 or year % 400 == 0)):
        month_days[1] = 29  # Update for leap year

    if not (1 <= day <= month_days[month - 1]):
        raise ValueError(f"Day must be between 1 and {month_days[month - 1]} for month {month}, got {day}.")

    return f"{day:02d}-{month:02d}-{year}"

