    if not isinstance(n, int):
        raise TypeError("The input must be an integer.")
    if n < 0:
        raise ValueError("The input must be a non-negative integer.")
    if n <= 1:
        return 1

    last_digit = 1
    for i in range(2, n + 1):
        last_digit = (last_digit * (i % 10)) % 10
        if last_digit == 0:
            break

    return last_digit

