def cube_Sum(n):
    # Handle string inputs
    if isinstance(n, str):
        try:
            # Try to convert string to integer
            n = int(float(n))
        except ValueError:
            raise ValueError("String input must represent a valid number")

    # Type validation (after string conversion)
    if not isinstance(n, int):
        raise TypeError("Input must be an integer or string representing an integer")

    # Value validation
    if n < 1:
        raise ValueError("Input must be a positive integer")

    total = 0
    for i in range(1, n + 1):
        even_number = 2 * i
        total += even_number ** 3
    return total

