def search(self, arr):
    logger.debug(f"Search called with arguments: {arr}")
    self.stats['calls'] += 1

    # Input validation
    if not isinstance(arr, list):
        logger.warning(f"Invalid input type: {type(arr)}")
        self.stats['errors'] += 1
        raise TypeError("Input must be a list.")
    if len(arr) == 0:
        logger.warning("Empty list provided.")
        self.stats['errors'] += 1
        raise ValueError("List cannot be empty.")
    if len(arr) % 2 == 0:
        logger.warning("List has even number of elements.")
        self.stats['errors'] += 1
        raise ValueError("List must have an odd number of elements.")
    processed = []
    for num in arr:
        if isinstance(num, str):
            try:
                num = float(num)
            except ValueError:
                logger.warning(f"String '{num}' cannot be converted to a number.")
                self.stats['errors'] += 1
                raise ValueError(f"String '{num}' cannot be converted to a number.")
        elif not isinstance(num, (int, float)):
            logger.warning(f"Invalid element type: {type(num)}")
            self.stats['errors'] += 1
            raise TypeError("All elements must be numbers.")
        processed.append(num)
    # Check if the list is sorted
    for i in range(len(processed) - 1):
        if processed[i] > processed[i + 1]:
            logger.warning("List is not sorted in non-decreasing order.")
            self.stats['errors'] += 1
            raise ValueError("List must be sorted in non-decreasing order.")

    # Create cache key
    cache_key = tuple(processed)

    # Check cache
    if cache_key in self._cache:
        logger.debug(f"Cache hit for key: {cache_key}")
        self.stats['cache_hits'] += 1
        return self._cache[cache_key]

    # Handle the case where the array has only one element
    if len(processed) == 1:
        result = processed[0]
    else:
        # Iterate through the array to find the single occurrence element
        for i in range(len(processed)):
            if i == 0:
                if processed[i] != processed[i + 1]:
                    result = processed[i]
                    break
            elif i == len(processed) - 1:
                if processed[i] != processed[i - 1]:
                    result = processed[i]
                    break
            else:
                if processed[i] != processed[i - 1] and processed[i] != processed[i + 1]:
                    result = processed[i]
                    break

    # Store result in cache
    self._cache[cache_key] = result
    return result

