import math
from scipy.optimize import bisect

_cache = {}

def poly(xs: list, x: float):
    """
    Evaluates polynomial with coefficients xs at point x.
    return xs[0] + xs[1] * x + xs[2] * x^2 + .... xs[n] * x^n
    """
    return sum([coeff * math.pow(x, i) for i, coeff in enumerate(xs)])

def find_zero(xs: list):
    """ xs are coefficients of a polynomial.
    find_zero finds x such that poly(x) = 0.
    find_zero returns only one zero point, even if there are many.
    Moreover, find_zero only takes list xs having even number of coefficients
    and largest non zero coefficient as it guarantees a solution.
    """
    # Input validation
    if not isinstance(xs, list):
        raise TypeError("The argument xs must be a list.")

    # Convert string representations to floats and validate
    converted_xs = []
    for coeff in xs:
        if isinstance(coeff, (int, float)):
            converted_xs.append(float(coeff))
        elif isinstance(coeff, str):
            try:
                converted_xs.append(float(coeff))
            except ValueError:
                raise ValueError(f"String '{coeff}' cannot be converted to a float.")
        else:
            raise TypeError("All coefficients in xs must be integers, floats, or convertible strings.")

    if len(converted_xs) % 2 != 0:
        raise ValueError("The list must have an even number of coefficients.")
    if converted_xs[-1] == 0:
        raise ValueError("The largest non-zero coefficient must be non-zero.")

    # Create a cache key from the converted coefficients
    cache_key = tuple(converted_xs)

    # Check if the result is already cached
    if cache_key in _cache:
        return _cache[cache_key]

    # Define a function for the polynomial
    def f(x):
        return poly(converted_xs, x)

    # Use the bisection method to find a root
    # We assume a reasonable interval [-1000, 1000] for the root search
    result = bisect(f, -1000, 1000)

    # Cache the result
    _cache[cache_key] = result

    return result

def find_zero_batch(args_list):
    """ 
    Accepts a list of argument-tuples and returns a list of results by calling find_zero for each one.
    If any single call raises an exception, catch it and place None in the result list at that position.
    """
    results = []
    for args in args_list:
        try:
            result = find_zero(*args)
            results.append(result)
        except Exception:
            results.append(None)
    return results

def clear_cache():
    """Clears the cache of previously computed results."""
    _cache.clear()

