def change_date_format(date_str):
    if not isinstance(date_str, str):
        raise TypeError("Input must be a string.")

    if len(date_str) != 10 or date_str[4] != '-' or date_str[7] != '-':
        raise ValueError("Invalid date format. Expected yyyy-mm-dd.")

    parts = date_str.split('-')
    if len(parts) != 3:
        raise ValueError("Invalid date format. Expected yyyy-mm-dd.")

    year_str, month_str, day_str = parts

    try:
        year = float(year_str)
        month = float(month_str)
        day = float(day_str)
    except ValueError:
        raise ValueError("Invalid numeric string in date components.")

    if not (year.is_integer() and month.is_integer() and day.is_integer()):
        raise ValueError("Date components must be integers.")

    year = int(year)
    month = int(month)
    day = int(day)

    if year < 0 or month < 1 or month > 12 or day < 1 or day > 31:
        raise ValueError("Date components are out of range.")

    try:
        from datetime import datetime
        datetime(year, month, day)
    except ValueError as e:
        raise ValueError(f"Invalid date: {e}")

    return f"{day:02d}-{month:02d}-{year}"

