    def __init__(self):
        self._cache = {}

    def maxAverageOfPath(self, matrix):
        if not isinstance(matrix, list):
            raise TypeError("The matrix must be a list of lists.")
        if not matrix or not isinstance(matrix[0], list):
            raise ValueError("The matrix must be a non-empty square list of lists.")

        N = len(matrix)
        for row in matrix:
            if not isinstance(row, list):
                raise TypeError("Each row in the matrix must be a list.")
            if len(row) != N:
                raise ValueError("The matrix must be square (same number of rows and columns).")
            for cell in row:
                if isinstance(cell, str):
                    try:
                        cell = float(cell)
                    except ValueError:
                        raise ValueError(f"Cannot convert string '{cell}' to a number.")
                if not isinstance(cell, (int, float)):
                    raise TypeError("Each cell in the matrix must be an integer, float, or a numeric string.")

        # Convert matrix to a hashable form for caching
        matrix_key = tuple(tuple(float(cell) for cell in row) for row in matrix)

        if matrix_key in self._cache:
            return self._cache[matrix_key]

        dp = [[0] * N for _ in range(N)]
        path_count = [[0] * N for _ in range(N)]

        dp[0][0] = float(matrix[0][0])
        path_count[0][0] = 1

        for i in range(1, N):
            dp[i][0] = dp[i-1][0] + float(matrix[i][0])
            path_count[i][0] = path_count[i-1][0] + 1

        for j in range(1, N):
            dp[0][j] = dp[0][j-1] + float(matrix[0][j])
            path_count[0][j] = path_count[0][j-1] + 1

        for i in range(1, N):
            for j in range(1, N):
                if dp[i-1][j] > dp[i][j-1]:
                    dp[i][j] = dp[i-1][j] + float(matrix[i][j])
                    path_count[i][j] = path_count[i-1][j] + 1
                else:
                    dp[i][j] = dp[i][j-1] + float(matrix[i][j])
                    path_count[i][j] = path_count[i][j-1] + 1

        total_cost = dp[N-1][N-1]
        total_cells = path_count[N-1][N-1]
        result = total_cost / total_cells

        self._cache[matrix_key] = result
        return result

    def maxAverageOfPath_batch(self, arg_list):
        results = []
        for args in arg_list:
            try:
                result = self.maxAverageOfPath(*args)
                results.append(result)
            except Exception:
                results.append(None)
        return results

    def clear_cache(self):
        self._cache.clear()

