def search(nums):
    left, right = 0, len(nums) - 1

    while left < right:
        mid = left + (right - left) // 2

        # Ensure mid is even for comparison with the next element
        if mid % 2 == 1:
            mid -= 1

        # Check if the pair is broken
        if nums[mid] != nums[mid + 1]:
            right = mid
        else:
            left = mid + 2

    return nums[left]

