class PackConsecutiveDuplicatesProcessor:
    def __init__(self):
        self._cache = {}
        self.logger = logging.getLogger('pack_consecutive_duplicates')
        self.stats = {
            'calls': 0,
            'cache_hits': 0,
            'errors': 0
        }

    def pack_consecutive_duplicates(self, lst):
        self.logger.debug("Called with arguments: %s", lst)
        self.stats['calls'] += 1

        if not isinstance(lst, list):
            raise TypeError("Input must be a list.")

        converted_lst = []
        for num in lst:
