            result = []
        else:
            result = []
            current_group = [converted_lst[0]]
            for num in converted_lst[1:]:
                if num == current_group[-1]:
                    current_group.append(num)
                else:
                    result.append(current_group)
                    current_group = [num]
            result.append(current_group)

        self._cache[key] = result
        return result

    def pack_consecutive_duplicates_batch(self, arg_tuples):
