import math
from scipy.optimize import bisect

def poly(xs: list, x: float):
    """
    Evaluates polynomial with coefficients xs at point x.
    return xs[0] + xs[1] * x + xs[2] * x^2 + .... xs[n] * x^n
    """
    return sum([coeff * math.pow(x, i) for i, coeff in enumerate(xs)])

def find_zero(xs: list):
    """ xs are coefficients of a polynomial.
    find_zero finds x such that poly(x) = 0.
    find_zero returns only one zero point, even if there are many.
    Moreover, find_zero only takes list xs having even number of coefficients
    and largest non zero coefficient as it guarantees a solution.
    """
    if len(xs) % 2 != 0 or xs[-1] == 0:
        raise ValueError("The list must have an even number of coefficients and the largest non-zero coefficient.")

    # Define a function for the polynomial
    def f(x):
        return poly(xs, x)

    # Use the bisection method to find a root
    # We assume a reasonable interval [-1000, 1000] for the root search
    return bisect(f, -1000, 1000)

def intersection(interval1, interval2):
    """You are given two intervals,
    where each interval is a pair of integers. For example, interval = (start, end) = (1, 2).
    The given intervals are closed which means that the interval (start, end)
    includes both start and end.
    For each given interval, it is assumed that its start is less or equal its end.
    Your task is to determine whether the length of intersection of these two 
    intervals is a prime number.
    Example, the intersection of the intervals (1, 3), (2, 4) is (2, 3)
    which its length is 1, which not a prime number.
    If the length of the intersection is a prime number, return "YES",
    otherwise, return "NO".
    If the two intervals don't intersect, return "NO".
    """
    # Helper function to convert input to integer
    def convert_to_int(value):
        """Convert value to integer, handling strings and numeric types."""
        if isinstance(value, str):
            try:
                # Try to convert string to float first, then to int
                float_val = float(value)
                int_val = int(float_val)
                # Check if conversion is lossless
                if float_val != int_val:
                    raise ValueError(f"Cannot convert '{value}' to integer without loss of precision")
                return int_val
            except ValueError as e:
                if "loss of precision" in str(e):
                    raise
                raise ValueError(f"Cannot convert '{value}' to integer")
        elif isinstance(value, (int, float)):
            # For float values, check if conversion is lossless
            if isinstance(value, float):
                int_val = int(value)
                if value != int_val:
                    raise ValueError(f"Cannot convert {value} to integer without loss of precision")
                return int_val
            return value
        else:
            raise TypeError(f"Cannot convert {type(value).__name__} to integer")

    # Input validation
    # Check type of arguments
    if not isinstance(interval1, tuple) or not isinstance(interval2, tuple):
        raise TypeError("Both arguments must be tuples")

    # Check length of tuples
    if len(interval1) != 2 or len(interval2) != 2:
        raise ValueError("Both intervals must be tuples of length 2")

    # Convert and validate interval values
    converted_intervals = []
    for i, interval in enumerate([interval1, interval2], 1):
        try:
            start_val = convert_to_int(interval[0])
            end_val = convert_to_int(interval[1])
            converted_intervals.append((start_val, end_val))
        except (TypeError, ValueError) as e:
            # Re-raise with more specific message
            if isinstance(e, TypeError):
                raise TypeError(f"Interval {i}: {str(e)}")
            else:
                raise ValueError(f"Interval {i}: {str(e)}")

    # Update intervals with converted values
    interval1, interval2 = converted_intervals

    # Check that start <= end for each interval
    for i, interval in enumerate([interval1, interval2], 1):
        if interval[0] > interval[1]:
            raise ValueError(f"Interval {i}: start must be less than or equal to end")

    # Find intersection boundaries
    start = max(interval1[0], interval2[0])
    end = min(interval1[1], interval2[1])

    # Check if intervals intersect
