                    raise ValueError("The message must contain only alphabetic characters.")
        else:
            raise TypeError("The message must be a string.")

        # Check if the result is already in the cache
        if message in self._cache:
            return self._cache[message]

        vowels = 'aeiouAEIOU'
        shift_vowels = {'a': 'c', 'e': 'g', 'i': 'k', 'o': 'q', 'u': 'w',
                        'A': 'C', 'E': 'G', 'I': 'K', 'O': 'Q', 'U': 'W'}

        encoded_message = []

        for char in message:
            if char in vowels:
                # Replace vowel with the corresponding shifted vowel
                encoded_message.append(shift_vowels[char])
            else:
                # Swap case for non-vowel characters
                encoded_message.append(char.swapcase())

        result = ''.join(encoded_message)
        self._cache[message] = result
        return result

