                if not numeric.is_integer():
                    raise ValueError("Input string does not represent an integer.")
                n = int(numeric)
            except ValueError as e:
                self.logger.warning(f"Invalid string input: {e}")
                raise
        elif not isinstance(n, int):
            self.logger.warning("Input must be an integer or a string representing an integer.")
            raise TypeError("Input must be an integer or a string representing an integer.")

        # Check if n is non-negative
        if n < 0:
            self.logger.warning("Input must be a non-negative integer.")
            raise ValueError("Input must be a non-negative integer.")

        # Check cache
        if n in self._cache:
            self.logger.debug(f"Cache hit for argument: {n}")
            self.stats['cache_hits'] += 1
            return self._cache[n]

