        if int(candidate) > n:
            self._cache[n] = int(candidate)
            return int(candidate)
        else:
            incremented = str(int(left) + 1)
            candidate = incremented + incremented[:-1][::-1]
            self._cache[n] = int(candidate)
            return int(candidate)

