        """
        Accepts a list of argument-tuples and returns a list of results by calling `smallest_change` for each one.
        If any single call raises an exception, catch it and place `None` in the result list at that position.
        """
        results = []
        for args in arg_tuples:
            try:
                result = self.smallest_change(args)
                results.append(result)
            except Exception:
                results.append(None)
        return results

    def clear_cache(self):
        self._cache.clear()

    def get_stats(self):
        return self.stats.copy()

