class TriProcessor:
    def __init__(self):
        self.logger = logging.getLogger('tri')
        self._cache = {}
        self.stats = {'calls': 0, 'cache_hits': 0, 'errors': 0}

    def clear_cache(self):
        """Clear the internal cache."""
        self._cache.clear()

    def get_stats(self):
        """Return a copy of the statistics dictionary."""
        return self.stats.copy()

    def tri(self, n):
        """Everyone knows Fibonacci sequence, it was studied deeply by mathematicians in 
        the last couple centuries. However, what people don't know is Tribonacci sequence.
        Tribonacci sequence is defined by the recurrence:
        tri(1) = 3
        tri(n) = 1 + n / 2, if n is even.
        tri(n) =  tri(n - 1) + tri(n - 2) + tri(n + 1), if n is odd.
        For example:
        tri(2) = 1 + (2 / 2) = 2
        tri(4) = 1 + (4 / 2) = 3
        tri(3) = tri(2) + tri(1) + tri(4)
               = 2 + 3 + 3 = 8 
        You are given a non-negative integer number n, you have to a return a list of the 
        first n + 1 numbers of the Tribonacci sequence.
        Examples:
        tri(3) = [1, 3, 2, 8]
        """
        self.logger.debug(f"Calling tri with n={n}")
        self.stats['calls'] += 1

        try:
            # Handle string input
            if isinstance(n, str):
                try:
                    n_float = float(n)
                except ValueError:
                    raise ValueError(f"Invalid string input: {n}")
                if not n_float.is_integer():
                    raise ValueError(f"String input '{n}' must represent an integer")
                n = int(n_float)

            # Validate type
            if not isinstance(n, int):
                raise TypeError("n must be an integer")

            # Validate value
            if n < 0:
                raise ValueError("n must be a non-negative integer")

            # Check cache
            if n in self._cache:
                self.logger.debug(f"Cache hit for n={n}")
                self.stats['cache_hits'] += 1
                return self._cache[n]

            # Compute result
            if n == 0:
                result = [1]
            elif n == 1:
                result = [1, 3]
            else:
                dp = [0] * (n + 1)
                dp[0] = 1
                dp[1] = 3
                for i in range(2, n + 1):
                    if i % 2 == 0:
                        dp[i] = 1 + (i // 2)
                    else:
                        next_term = 1 + ((i + 1) // 2)
                        dp[i] = dp[i - 1] + dp[i - 2] + next_term
                result = dp

            self._cache[n] = result
            return result

        except Exception as e:
            self.logger.warning(f"Exception in tri: {e}", exc_info=True)
            self.stats['errors'] += 1
            raise

    def tri_batch(self, args_list):
        """Process a list of argument-tuples by calling `tri` for each one.
        Returns a list of results, with `None` for any calls that raise exceptions.
        """
        results = []
        for args in args_list:
            try:
                res = self.tri(*args)
                results.append(res)
            except Exception:
                results.append(None)
        return results

