        self.logger = logging.getLogger('replace_list')
        logging.basicConfig(level=logging.DEBUG)

    def replace_list(self, list1, list2):
        """
        Optimized to avoid unnecessary list slicing and concatenation.
        Instead of slicing and concatenating lists, directly construct the result
        by appending elements from list2 to list1 up to the second last element.
        This reduces the overhead of creating intermediate lists.
        """
        self.logger.debug(f"Called replace_list with arguments: {list1}, {list2}")
        self.stats['calls'] += 1

        def convert_to_number(item):
            if isinstance(item, (int, float)):
                return item
            if isinstance(item, str):
                try:
                    return float(item) if '.' in item else int(item)
                except ValueError:
                    raise ValueError(f"Cannot convert '{item}' to a number.")
            raise TypeError(f"Invalid type: {type(item)}. Expected int, float, or str.")

        def make_hashable(lst):
            return tuple(convert_to_number(item) for item in lst)

        if not isinstance(list1, list):
            raise TypeError("The first argument must be a list.")
        if not isinstance(list2, list):
            raise TypeError("The second argument must be a list.")

        hashable_list1 = make_hashable(list1)
        hashable_list2 = make_hashable(list2)
        cache_key = (hashable_list1, hashable_list2)

        if cache_key in self._cache:
            self.logger.debug("Cache hit for key: {}".format(cache_key))
            self.stats['cache_hits'] += 1
            return self._cache[cache_key]

        try:
            list1 = [convert_to_number(item) for item in list1]
            list2 = [convert_to_number(item) for item in list2]

            if not list1:
                result = list2
            else:
                result = list1[:-1] + list2

            self._cache[cache_key] = result
            return result
        except Exception as e:
            self.logger.warning(f"Exception occurred: {e}")
            self.stats['errors'] += 1
            raise

    def clear_cache(self):
        self._cache.clear()

    def replace_list_batch(self, argument_tuples):
        results = []
        for args in argument_tuples:
            try:
                if not isinstance(args, tuple) or len(args) != 2:
                    raise ValueError("Each argument must be a tuple of two lists.")
                result = self.replace_list(*args)
            except Exception:
                result = None
            results.append(result)
        return results

    def get_stats(self):
        return deepcopy(self.stats)

