    def is_multiply_prime(self, a):
        """Write a function that returns true if the given number is the multiplication of 3 prime numbers
        and false otherwise.
        Knowing that (a) is less then 100. 
        Example:
        is_multiply_prime(30) == True
        30 = 2 * 3 * 5
        """
        self.logger.debug(f"Call to is_multiply_prime with a={a}")
        self.stats['calls'] += 1
        try:
            # Handle string and numeric inputs
            if isinstance(a, str):
                try:
                    num = float(a)
                    if not num.is_integer():
                        raise ValueError(f"Input string '{a}' must represent an integer.")
                    a = int(num)
                except ValueError:
                    raise ValueError(f"Invalid string input: {a}")
            elif isinstance(a, float):
                if not a.is_integer():
                    raise ValueError(f"Input float {a} must be an integer.")
                a = int(a)
            elif not isinstance(a, int):
                raise TypeError(f"Input must be an integer or a string/float representing an integer, got {type(a)} instead.")

            # Now a is an integer, proceed with original validation
            if a < 1:
                raise ValueError("Input must be a positive integer.")
            if a >= 100:
                raise ValueError("Input must be less than 100.")

            # Check cache
            if a in self._cache:
                self.logger.debug(f"Cache hit for a={a}")
                self.stats['cache_hits'] += 1
                return self._cache[a]

            if a < 8:
                # Store in cache
                self._cache[a] = False
                return False

            # Generate primes up to a
            def sieve(n):
                sieve = [True] * (n+1)
                sieve[0] = sieve[1] = False
                for i in range(2, int(n**0.5)+1):
                    if sieve[i]:
                        for j in range(i*i, n+1, i):
                            sieve[j] = False
                primes = [i for i, is_prime in enumerate(sieve) if is_prime]
                return primes

            primes = sieve(a)

            # Check all possible triplets (p, q, r) with p <= q <= r
            result = False
