class IndexMultiplicationProcessor:
    """
    A class to perform index-wise multiplication of nested tuples with validation, caching, logging, and statistics.

    Optimization Strategy:
    - Pre-convert all inner elements to floats in a single pass to avoid repeated calls to float() during multiplication.
    - This reduces redundant computations and improves time complexity by separating validation/conversion from multiplication.
    - The result is stored in a new structure of floats, which is then converted to tuples for output.
    """

    def __init__(self):
        self._cache = {}
        self.stats = {'calls': 0, 'cache_hits': 0, 'errors': 0}

    def clear_cache(self):
        """Clears the cache."""
        self._cache.clear()

    def index_multiplication(self, t1, t2):
        self.stats['calls'] += 1
        logger.debug(f"Calling index_multiplication with arguments: t1={t1}, t2={t2}")

        # Validate input types
        if not (isinstance(t1, tuple) and isinstance(t2, tuple)):
            logger.warning(f"Invalid input types: t1={t1}, t2={t2}")
            raise TypeError("Both arguments must be tuples.")

        # Validate structure and convert to floats in one pass
        try:
            converted_t1 = []
            converted_t2 = []
            for inner_t1, inner_t2 in zip(t1, t2):
                if len(inner_t1) != len(inner_t2):
                    logger.warning(f"Inner tuples have different lengths: {inner_t1}, {inner_t2}")
                    raise ValueError("Corresponding inner tuples must have the same length.")

                converted_inner_t1 = []
                converted_inner_t2 = []
                for a, b in zip(inner_t1, inner_t2):
                    # Validate and convert each element
                    if isinstance(a, str):
                        try:
                            a = float(a)
                        except ValueError:
                            logger.warning(f"Invalid string value: {a}")
                            raise ValueError(f"String value '{a}' cannot be converted to a number.")
                    elif not isinstance(a, (int, float)):
                        logger.warning(f"Invalid element type: {a}")
                        raise TypeError("Each element of the inner tuple must be a number (int or float) or a string representing a number.")

                    if isinstance(b, str):
                        try:
                            b = float(b)
                        except ValueError:
                            logger.warning(f"Invalid string value: {b}")
                            raise ValueError(f"String value '{b}' cannot be converted to a number.")
                    elif not isinstance(b, (int, float)):
                        logger.warning(f"Invalid element type: {b}")
                        raise TypeError("Each element of the inner tuple must be a number (int or float) or a string representing a number.")

                    converted_inner_t1.append(a)
                    converted_inner_t2.append(b)

                converted_t1.append(tuple(converted_inner_t1))
                converted_t2.append(tuple(converted_inner_t2))
        except Exception as e:
            logger.warning(f"Validation or conversion failed: {e}")
            raise

        # Create a hashable key from the arguments
        key = (converted_t1, converted_t2)

        # Check if the result is already in the cache
        if key in self._cache:
            logger.debug(f"Cache hit for key: {key}")
            self.stats['cache_hits'] += 1
            return self._cache[key]

        # Perform index-wise multiplication
        result = tuple(tuple(a * b for a, b in zip(inner1, inner2)) for inner1, inner2 in zip(converted_t1, converted_t2))

        # Store the result in the cache
        self._cache[key] = result

        return result

    def index_multiplication_batch(self, arg_list):
        results = []
        for args in arg_list:
            try:
                # Ensure args is a tuple of two elements
                if not (isinstance(args, tuple) and len(args) == 2):
                    logger.warning(f"Invalid batch argument: {args}")
                    raise TypeError("Each element of the batch list must be a tuple of two arguments.")
                t1, t2 = args
                res = self.index_multiplication(t1, t2)
                results.append(res)
            except Exception:
                logger.warning(f"Exception occurred for arguments: {args}")
                self.stats['errors'] += 1
                results.append(None)
        return results

    def get_stats(self):
        """Returns a copy of the statistics dictionary."""
        return self.stats.copy()

