from itertools import combinations

def find_combinations(tuple_list):
    result = []
    for i in range(1, len(tuple_list) + 1):
        for combo in combinations(tuple_list, i):
            sum_sums = sum(t[0] for t in combo)
            sum_products = sum(t[1] for t in combo)
            result.append((sum_sums, sum_products))
    return result

