        raise TypeError("All elements in the list must be numbers.")
    if not isinstance(n, int):
        raise TypeError("The second argument must be an integer.")
    if n < 0 or n >= len(lst):
        raise ValueError("The second argument must be a non-negative integer less than the list length.")
    if len(lst) < 2:
        raise ValueError("The list must contain at least two elements.")
    return sum(x ^ y for i, x in enumerate(lst) for j, y in enumerate(lst) if i < j and n <= i + j < len(lst))

def starts_one_ends(n):
    """
    Given a positive integer n, return the count of the numbers of n-digit
    positive integers that start or end with 1.
    """
    if not isinstance(n, int):
        raise TypeError("Input 'n' must be an integer.")
    if n <= 0:
        raise ValueError("Input 'n' must be a positive integer.")
    if n == 1:
        return 2
    else:
        return 9 * (10 ** (n - 2)) + 2 * (10 ** (n - 1))

