            handler = logging.StreamHandler()
            formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')
            handler.setFormatter(formatter)
            self.logger.addHandler(handler)
        self.logger.setLevel(logging.DEBUG)

    def surface_Area(self, base_edge, height):
        """
        Calculate the surface area of a square pyramid using an optimized approach.

        Optimization Strategy:
        - Precompute the base area and slant height only once.
        - Use the formula for lateral area directly without redundant calculations.
        - This reduces the number of operations and improves clarity.
        """
        self.stats['calls'] += 1
        self.logger.debug(f"Called surface_Area with base_edge={base_edge}, height={height}")

        def convert_to_number(value, name):
            if isinstance(value, (int, float)):
                return value
            if isinstance(value, str):
                try:
                    return float(value)
                except ValueError:
                    raise ValueError(f"{name} must be a number or a string representation of a number.")
            raise TypeError(f"{name} must be a number (int or float) or a string representation of a number.")

        try:
