            height = convert_to_number(height, "height")

            if base_edge <= 0:
                raise ValueError("base_edge must be a positive number.")
            if height <= 0:
                raise ValueError("height must be a positive number.")

            cache_key = (base_edge, height)
            if cache_key in self._cache:
                self.stats['cache_hits'] += 1
                self.logger.debug(f"Cache hit for key: {cache_key}")
                return self._cache[cache_key]

            # Optimized calculation
            base_area = base_edge ** 2
            half_base = base_edge / 2
            slant_height = math.sqrt(half_base ** 2 + height ** 2)
            lateral_area = base_edge * slant_height * 2
            total_surface_area = base_area + lateral_area

            self._cache[cache_key] = total_surface_area
            return total_surface_area
        except Exception as e:
            self.stats['errors'] += 1
            self.logger.warning(f"Exception occurred: {e}")
            raise

    def surface_Area_batch(self, arguments_list):
        results = []
        for args in arguments_list:
            try:
                result = self.surface_Area(*args)
            except Exception:
                result = None
            results.append(result)
        return results

    def clear_cache(self):
        self._cache.clear()

    def get_stats(self):
        return deepcopy(self.stats)

